var data = ($.steps.scrapeBlog.response && $.steps.scrapeBlog.response.data) ? $.steps.scrapeBlog.response.data : {};
var markdown = (data.markdown || '').slice(0, 5000);
var title = data.metadata && data.metadata.title ? data.metadata.title : '';
return { markdown: markdown, title: title, contentLength: markdown.length };

var content = $.steps.extractVoice.output;
var prompt = 'You are an expert content strategist and blog writer. You will analyze an existing blog post to understand the brand voice, then write a new blog post in that same style.

';
prompt += 'STEP 1 - ANALYZE THIS EXISTING BLOG POST FOR BRAND VOICE:
';
prompt += 'Title: ' + content.title + '
';
prompt += 'Content:
' + content.markdown + '

';
prompt += 'STEP 2 - WRITE A NEW BLOG POST:
';
prompt += 'Topic: ' + $.input.blogTopic + '
';
prompt += 'Target Audience: ' + ($.input.targetAudience || 'general business audience') + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- First identify the brand voice characteristics (tone, sentence structure, vocabulary level, use of examples, formatting style)
';
prompt += '- Then write a complete new blog post on the given topic matching that voice exactly
';
prompt += '- Include a compelling title, introduction, 3-5 main sections with subheadings, and a conclusion
';
prompt += '- Match the approximate length and structure of the original

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "voiceAnalysis": {
';
prompt += '    "tone": "description of tone",
';
prompt += '    "style": "description of writing style",
';
prompt += '    "vocabulary": "vocabulary level",
';
prompt += '    "keyCharacteristics": ["trait1", "trait2"]
';
prompt += '  },
';
prompt += '  "newPost": {
';
prompt += '    "title": "Blog post title",
';
prompt += '    "content": "Full markdown blog post content",
';
prompt += '    "metaDescription": "SEO meta description under 160 chars",
';
prompt += '    "suggestedTags": ["tag1", "tag2"]
';
prompt += '  }
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { voiceAnalysis: {}, newPost: { title: 'Generated Post', content: raw, metaDescription: '', suggestedTags: [] } }; }

var ai = $.steps.parseAI.output;
var voice = ai.voiceAnalysis || {};
var post = ai.newPost || {};
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'New Blog Draft Ready', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Title:* ' + (post.title || 'Untitled') } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Topic:* ' + $.input.blogTopic + '\n*Voice Source:* <' + $.input.blogUrl + '|Original Post>' } });
blocks.push({ type: 'divider' });
if (voice.tone) {
  var voiceText = '*Brand Voice Analysis:*\n';
  voiceText += '- Tone: ' + voice.tone + '\n';
  voiceText += '- Style: ' + (voice.style || '') + '\n';
  voiceText += '- Vocabulary: ' + (voice.vocabulary || '') + '\n';
  if (voice.keyCharacteristics && voice.keyCharacteristics.length > 0) {
    voiceText += '- Key traits: ' + voice.keyCharacteristics.join(', ');
  }
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: voiceText.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}
var contentPreview = (post.content || '').slice(0, 2500);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Blog Content:*\n' + contentPreview } });
if (post.metaDescription) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Meta Description:* ' + post.metaDescription } });
}
if (post.suggestedTags && post.suggestedTags.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Tags:* ' + post.suggestedTags.join(', ') } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Generated with Firecrawl + Claude AI via One CLI' }] });
var fallback = 'Blog Draft: ' + (post.title || $.input.blogTopic);
return { blocks: blocks, fallback: fallback };
